#include <iostream>
#include <stack>
using namespace std;
stack<int> a;
int main()
{
    string s;
    getline(cin,s,'@');
    int num=0,xian,hou;
    for(int i=0;i<=s.size()-1;i++)
    {
        if(s[i]>='0'&&s[i]<='9')
        {
            num=num*10+s[i]-'0';
        }
        else if(s[i]=='.')
        {
            a.push(num);
            num=0;
        }
        else
        {
            hou=a.top();
            a.pop();
            xian=a.top();
            a.pop();
            if(s[i]=='+')
            {
                a.push(xian+hou);
            }
            else if(s[i]=='-')
            {
                a.push(xian-hou);
            }
            else if(s[i]=='*')
            {
                a.push(xian*hou);
            }
            else
            {
                a.push(xian/hou);
            }
        }
    }
    cout<<a.top();
    return 0;
}
